--
-- Name: extract_location_from_metadata(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.extract_location_from_metadata() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Se tiver dados de localização no metadata, extrair para colunas separadas
    IF NEW.metadata ? 'location' THEN
        NEW.country = NEW.metadata->'location'->>'country';
        NEW.region = NEW.metadata->'location'->>'region';
        NEW.city = NEW.metadata->'location'->>'city';
        NEW.timezone = NEW.metadata->'location'->>'timezone';
        
        IF NEW.metadata->'location'->>'latitude' IS NOT NULL AND 
           NEW.metadata->'location'->>'latitude' != 'null' THEN
            NEW.latitude = (NEW.metadata->'location'->>'latitude')::DECIMAL(10, 8);
        END IF;
        
        IF NEW.metadata->'location'->>'longitude' IS NOT NULL AND 
           NEW.metadata->'location'->>'longitude' != 'null' THEN
            NEW.longitude = (NEW.metadata->'location'->>'longitude')::DECIMAL(11, 8);
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.extract_location_from_metadata() OWNER TO postgres;

--
-- Name: generate_affiliate_code(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.generate_affiliate_code() RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    code TEXT;
    chars TEXT := 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    result TEXT := '';
    i INTEGER;
BEGIN
    LOOP
        result := '';
        FOR i IN 1..8 LOOP
            result := result || substr(chars, floor(random() * length(chars) + 1)::int, 1);
        END LOOP;
        code := 'AFF-' || result;
        EXIT WHEN NOT EXISTS (SELECT 1 FROM affiliates WHERE affiliate_code = code);
    END LOOP;
    RETURN code;
END;
$$;


ALTER FUNCTION public.generate_affiliate_code() OWNER TO postgres;

--
-- Name: generate_app_slug(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.generate_app_slug(app_name text) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
  base_slug TEXT;
  final_slug TEXT;
  counter INTEGER := 0;
BEGIN
  -- Convert name to slug format
  base_slug := lower(regexp_replace(
    regexp_replace(
      unaccent(trim(app_name)), 
      '[^a-zA-Z0-9\s-]', '', 'g'
    ), 
    '\s+', '-', 'g'
  ));
  
  final_slug := base_slug;
  
  -- Check if slug exists and increment counter if needed
  WHILE EXISTS (SELECT 1 FROM public.applications WHERE slug = final_slug) LOOP
    counter := counter + 1;
    final_slug := base_slug || '-' || counter;
  END LOOP;
  
  RETURN final_slug;
END;
$$;


ALTER FUNCTION public.generate_app_slug(app_name text) OWNER TO postgres;

--
-- Name: generate_funnel_slug(text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.generate_funnel_slug(funnel_name text, owner_uuid uuid) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    base_slug text;
    final_slug text;
    counter integer := 0;
BEGIN
    -- Generate base slug from name
    base_slug := lower(regexp_replace(trim(funnel_name), '[^a-zA-Z0-9\s]', '', 'g'));
    base_slug := regexp_replace(base_slug, '\s+', '-', 'g');
    
    -- Limit length
    base_slug := left(base_slug, 50);
    
    -- Check if slug exists
    final_slug := base_slug;
    
    WHILE EXISTS (SELECT 1 FROM funnels WHERE slug = final_slug AND owner_id = owner_uuid) LOOP
        counter := counter + 1;
        final_slug := base_slug || '-' || counter;
    END LOOP;
    
    RETURN final_slug;
END;
$$;


ALTER FUNCTION public.generate_funnel_slug(funnel_name text, owner_uuid uuid) OWNER TO postgres;

--
-- Name: FUNCTION generate_funnel_slug(funnel_name text, owner_uuid uuid); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.generate_funnel_slug(funnel_name text, owner_uuid uuid) IS 'Gera um slug único para funis baseado no nome e owner_id';


--
-- Name: generate_marketplace_product_slug(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.generate_marketplace_product_slug(base_name text) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    slug TEXT;
    counter INTEGER := 0;
BEGIN
    -- Criar slug base
    slug := lower(regexp_replace(base_name, '[^a-zA-Z0-9]+', '-', 'g'));
    slug := trim(both '-' from slug);
    
    -- Verificar se já existe e adicionar contador se necessário
    WHILE EXISTS (SELECT 1 FROM marketplace_products WHERE marketplace_products.slug = slug) LOOP
        counter := counter + 1;
        slug := lower(regexp_replace(base_name, '[^a-zA-Z0-9]+', '-', 'g')) || '-' || counter;
        slug := trim(both '-' from slug);
    END LOOP;
    
    RETURN slug;
END;
$$;


ALTER FUNCTION public.generate_marketplace_product_slug(base_name text) OWNER TO postgres;

--
-- Name: generate_thankyou_token(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.generate_thankyou_token() RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    new_token TEXT;
    token_exists BOOLEAN;
BEGIN
    LOOP
        new_token := encode(
            digest(
                gen_random_uuid()::text || clock_timestamp()::text,
                'sha256'
            ),
            'hex'
        );
        
        SELECT EXISTS (
            SELECT 1 FROM user_product_access WHERE thankyou_token = new_token
        ) INTO token_exists;
        
        EXIT WHEN NOT token_exists;
    END LOOP;
    
    RETURN new_token;
END;
$$;


ALTER FUNCTION public.generate_thankyou_token() OWNER TO postgres;

