-- Name: increment_thankyou_view(text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.increment_thankyou_view(p_token text, p_purchase_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    UPDATE user_product_access
    SET 
        thankyou_views_count = thankyou_views_count + 1,
        thankyou_first_accessed_at = COALESCE(thankyou_first_accessed_at, NOW()),
        thankyou_last_accessed_at = NOW()
    WHERE id = p_purchase_id AND thankyou_token = p_token;
    
    RETURN FOUND;
END;
$$;


