--
-- Name: update_affiliate_stats(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_affiliate_stats() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        -- Nova venda
        UPDATE affiliates 
        SET 
            total_sales = total_sales + 1,
            total_earnings = total_earnings + NEW.commission_amount,
            pending_earnings = pending_earnings + NEW.commission_amount,
            last_sale_at = NEW.sale_date
        WHERE id = NEW.affiliate_id;
        
        -- Atualizar contador de vendas do produto
        UPDATE marketplace_products 
        SET sales_count = sales_count + 1 
        WHERE id = NEW.marketplace_product_id;
        
    ELSIF TG_OP = 'UPDATE' THEN
        -- Venda aprovada
        IF OLD.status != 'approved' AND NEW.status = 'approved' THEN
            UPDATE affiliates 
            SET 
                pending_earnings = pending_earnings - NEW.commission_amount,
                paid_earnings = paid_earnings + NEW.commission_amount
            WHERE id = NEW.affiliate_id;
        
        -- Venda reembolsada
        ELSIF OLD.status = 'approved' AND NEW.status = 'refunded' THEN
            UPDATE affiliates 
            SET 
                total_sales = GREATEST(0, total_sales - 1),
                total_earnings = total_earnings - NEW.commission_amount,
                paid_earnings = paid_earnings - NEW.commission_amount
            WHERE id = NEW.affiliate_id;
            
            UPDATE marketplace_products 
            SET sales_count = GREATEST(0, sales_count - 1)
            WHERE id = NEW.marketplace_product_id;
        END IF;
    END IF;
    
    RETURN NULL;
END;
$$;


ALTER FUNCTION public.update_affiliate_stats() OWNER TO postgres;

