-- Name: update_product_members_count(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_product_members_count() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        UPDATE marketplace_products 
        SET members_count = members_count + 1 
        WHERE id = NEW.marketplace_product_id;
    ELSIF TG_OP = 'DELETE' THEN
        UPDATE marketplace_products 
        SET members_count = GREATEST(0, members_count - 1)
        WHERE id = OLD.marketplace_product_id;
    END IF;
    RETURN NULL;
END;
$$;


