CREATE TABLE public.checkout_offers (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    checkout_id uuid,
    main_product_id uuid,
    product_id uuid NOT NULL,
    offer_type character varying(20) NOT NULL,
    offer_position integer DEFAULT 1 NOT NULL,
    is_active boolean DEFAULT true,
    discount_type character varying(20),
    discount_value numeric(10,2),
    custom_price numeric(10,2),
    title text,
    description text,
    image_url text,
    show_after_product_id uuid,
    show_if_accepted boolean,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    funnel_id uuid,
    original_price numeric(10,2),
    offer_price numeric(10,2),
    discount_percentage integer,
    currency character varying(3) DEFAULT 'BRL'::character varying,
    button_text text DEFAULT 'Aproveitar Esta Oferta'::text,
    offer_text text,
    product_name text,
    product_description text,
    show_product_image boolean DEFAULT false,
    checkout_offer_id uuid,
    offer_product_image text,
    page_id uuid,
    one_click_purchase boolean DEFAULT false,
    product_type character varying(20) DEFAULT 'member_area'::character varying,
    application_id uuid,
    CONSTRAINT checkout_offers_checkout_or_funnel_check CHECK ((((checkout_id IS NOT NULL) AND (funnel_id IS NULL)) OR ((checkout_id IS NULL) AND (funnel_id IS NOT NULL)) OR ((checkout_id IS NOT NULL) AND (funnel_id IS NOT NULL)))),
    CONSTRAINT checkout_offers_discount_type_check CHECK (((discount_type)::text = ANY ((ARRAY['percentage'::character varying, 'fixed'::character varying, 'none'::character varying])::text[]))),
    CONSTRAINT checkout_offers_main_not_offer CHECK ((main_product_id <> product_id)),
    CONSTRAINT checkout_offers_offer_type_check CHECK (((offer_type)::text = ANY ((ARRAY['order_bump'::character varying, 'upsell'::character varying, 'downsell'::character varying])::text[]))),
    CONSTRAINT checkout_offers_product_type_check CHECK (((product_type)::text = ANY ((ARRAY['member_area'::character varying, 'application'::character varying, 'app_product'::character varying])::text[]))),
    CONSTRAINT checkout_offers_valid_discount_value CHECK (((((discount_type)::text = 'percentage'::text) AND (discount_value > (0)::numeric) AND (discount_value <= (100)::numeric)) OR (((discount_type)::text = 'fixed'::text) AND (discount_value > (0)::numeric)) OR ((discount_type)::text = 'none'::text) OR (discount_type IS NULL)))
);


