--

CREATE TABLE public.member_areas (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    owner_id uuid NOT NULL,
    name character varying(255) NOT NULL,
    description text,
    slug character varying(255) NOT NULL,
    delivery_type public.delivery_type DEFAULT 'app'::public.delivery_type NOT NULL,
    status public.marketplace_product_status DEFAULT 'draft'::public.marketplace_product_status NOT NULL,
    price numeric(10,2) DEFAULT 0 NOT NULL,
    payment_type public.payment_type DEFAULT 'unique'::public.payment_type NOT NULL,
    recurrence_period public.recurrence_period DEFAULT 'monthly'::public.recurrence_period,
    marketplace_enabled boolean DEFAULT false NOT NULL,
    allow_affiliates boolean DEFAULT false NOT NULL,
    commission_percentage numeric(5,2) DEFAULT 30.00,
    sales_page_url text,
    image_url text,
    logo_url text,
    category character varying(100),
    sales_count integer DEFAULT 0 NOT NULL,
    views_count integer DEFAULT 0 NOT NULL,
    members_count integer DEFAULT 0 NOT NULL,
    affiliates_count integer DEFAULT 0 NOT NULL,
    community_settings jsonb DEFAULT '{}'::jsonb,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    payment_methods text[] DEFAULT ARRAY['credit_card'::text],
    default_payment_method text DEFAULT 'credit_card'::text,
    show_in_marketplace boolean DEFAULT false,
    currency character varying(3) DEFAULT 'USD'::character varying,
    support_enabled boolean DEFAULT false,
    support_label text DEFAULT 'Suporte'::text,
    support_description text DEFAULT 'Seg à Sex'::text,
    support_url text,
    refund_enabled boolean DEFAULT false,
    refund_label text DEFAULT 'Reembolso'::text,
    refund_url text,
    review_status text DEFAULT 'pending_review'::text,
    review_notes text,
    reviewed_at timestamp with time zone,
    reviewed_by uuid,
    offer_type character varying(50) DEFAULT 'main'::character varying,
    CONSTRAINT marketplace_products_commission_percentage_check CHECK (((commission_percentage >= (0)::numeric) AND (commission_percentage <= (100)::numeric))),
    CONSTRAINT marketplace_products_currency_check CHECK (((currency)::text = ANY ((ARRAY['USD'::character varying, 'EUR'::character varying, 'CHF'::character varying])::text[]))),
    CONSTRAINT marketplace_products_offer_type_check CHECK (((offer_type)::text = ANY ((ARRAY['main'::character varying, 'bonus'::character varying, 'order-bump'::character varying, 'upsell-downsell'::character varying])::text[]))),
    CONSTRAINT marketplace_products_review_status_check CHECK ((review_status = ANY (ARRAY['pending_review'::text, 'approved'::text, 'rejected'::text]))),
    CONSTRAINT marketplace_products_slug_check CHECK (((slug)::text ~* '^[a-z0-9-]+$'::text)),
    CONSTRAINT valid_default_payment_method CHECK ((default_payment_method = ANY (ARRAY['credit_card'::text, 'paypal'::text]))),
    CONSTRAINT valid_payment_methods CHECK (((payment_methods <@ ARRAY['credit_card'::text, 'paypal'::text]) AND (array_length(payment_methods, 1) > 0)))
);


