CREATE VIEW public.marketplace_products AS
 SELECT id,
    owner_id,
    name,
    description,
    slug,
    delivery_type,
    status,
    price,
    payment_type,
    recurrence_period,
    marketplace_enabled,
    allow_affiliates,
    commission_percentage,
    sales_page_url,
    image_url,
    logo_url,
    category,
    sales_count,
    views_count,
    members_count,
    affiliates_count,
    community_settings,
    created_at,
    updated_at,
    payment_methods,
    default_payment_method,
    show_in_marketplace,
    currency,
    support_enabled,
    support_label,
    support_description,
    support_url,
    refund_enabled,
    refund_label,
    refund_url,
    review_status,
    review_notes,
    reviewed_at,
    reviewed_by,
    offer_type
   FROM public.member_areas;


